    if chunk.endswith(b'\r\n'):
        chunk = chunk[:-2]
    elif chunk.endswith(b'\n'):
        chunk = chunk[:-1]
    try:
        dec = zlib.decompress(chunk)
    except Exception:
        continue
    if b'BT' not in dec:
        continue
    streams.append(dec)

def decode_pdf_string(bs: bytes) -> str:
    out = []
    i = 0
    while i < len(bs):
        c = bs[i]
        if c == 0x5c and i + 1 < len(bs):
            i += 1
            c2 = bs[i]
            mapping = {ord('n'): '\n', ord('r'): '\r', ord('t'): '\t', ord('b'): '\b', ord('f'): '\f', ord('('): '(', ord(')'): ')', ord('\\'): '\\'}
            if c2 in mapping:
